private matchRoute(method: string, pathname: string): { handler: RouteHandler; match: RouteMatch } | null {
  // Exact match first
  const exactRoutes = this.routes.get(pathname);
  if (exactRoutes) {
    for (const entry of exactRoutes) {
      if (entry.method === method || entry.method === '*') {
        return { handler: entry.handler, match: { pathname, params: {} } };
      }
    }
  }

  // Prefix match
  for (const entry of this.prefixRoutes) {
    if (pathname.startsWith(entry.prefix)) {
      if (entry.method === method || entry.method === '*') {
        const rest = pathname.substring(entry.prefix.length - 1); // includes the trailing /
        return { handler: entry.handler, match: { pathname, params: { wildcard: rest } } };
      }
    }
  }

  return null;
}
```

