```typescript
private handleRequestWithBody(req: http.IncomingMessage, res: http.ServerResponse, body: Buffer): void {
  try {
    const url = new URL(req.url || '/', `http://localhost:${this.port ?? 0}`);
    const pathname = url.pathname;
    const method = req.method ?? 'GET';

    // Handle OPTIONS (CORS preflight) - no auth needed
    if (method === 'OPTIONS') {
      this.handleCors(res);
      return;
    }

    // Auth check (skip for health endpoint)
    if (pathname !== '/health') {
      const authError = this.checkAuth(req);
      if (authError) {
        this.sendJsonResponse(res, authError.statusCode, {
          error: authError.message,
          code: authError.code,
        });
        return;
      }
    }

    // Parse JSON body for methods that have body
    let bodyString = body.toString('utf-8');
    let parsedBody: unknown = bodyString;

    if (body.length > 0 && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
      if (req.headers['content-type']?.includes('application/json')) {
        try {
          parsedBody = JSON.parse(bodyString);
        } catch {
          this.sendJsonResponse(res, 400, {
            error: 'Invalid JSON in request body',
            code: 'INVALID_JSON',
          });
          return;
        }
      }
    }

    // Route matching
    const matched = this.matchRoute(method, pathname);
    if (!matched) {
      this.sendJsonResponse(res, 404, {
        error: 'Not Found',
        code: 'NOT_FOUND',
        message: `Route ${method} ${pathname} not found`,
      });
      return;
    }

    // Reset idle timeout on each request
    this.refreshIdleTimeout();

    // Call handler
    const result = matched.handler(req, res, bodyString, matched.match);
    if (result instanceof Promise) {
      result.catch((err: unknown) => {
        this.handleHandlerError(res, err);
      });
    }
  } catch (err: unknown) {
    this.handleHandlerError(res, err);
  }
}
```

