export class HTTPServer {
  private server: http.Server | null = null;
  private port: number | null = null;
  private eventBus: EventBus | null = null;
  private token: string | null = null;
  private cas: ContentAddressableStorage;
  private config: DaemonConfig;
  private startTime: number = 0;

  // Routes
  private exactRoutes: Map<string, RouteEntry[]> = new Map();
  private prefixRoutes: PrefixRouteEntry[] = [];

  // SSE
  private sseClients: Map<string, http.ServerResponse> = new Map();
  private sseSubscription: { topic: string; unsubscribe: () => void } | null = null;
  private heartbeatInterval: ReturnType<typeof setInterval> | null = null;
  private readonly SSE_HEARTBEAT_INTERVAL = 30_000;

  // Idle timeout
  private idleTimeoutHandle: ReturnType<typeof setTimeout> | null = null;

  // Global error handlers
  private boundUncaughtHandler: ((err: Error) => void) | null = null;
  private boundUnhandledRejectionHandler: ((reason: unknown) => void) | null = null;

  constructor(config: DaemonConfig, eventBus?: EventBus) {
    this.config = config;
    this.eventBus = eventBus || null;
    this.cas = new ContentAddressableStorage();
    this.initRoutes();
  }

  private generateRequestId(): string {
    return Math.random().toString(36).substring(2, 15) + Date.now().toString(36);
  }

  // ── Route Registration ──

  private initRoutes(): void {
    // Exact match routes
    this.addExactRoute('GET', '/health', this.handleHealth.bind(this));
    this.addExactRoute('GET', '/events', this.handleSSE.bind(this));
    this.addExactRoute('GET', '/', this.handleRoot.bind(this));

    // Prefix routes for API v1
    const apiPrefix = '/api/v1/';
    this.addPrefixRoute('GET', `${apiPrefix}state/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('POST', `${apiPrefix}state/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('GET', `${apiPrefix}event/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('POST', `${apiPrefix}event/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('GET', `${apiPrefix}workflow/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('POST', `${apiPrefix}workflow/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('GET', `${apiPrefix}blob/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('POST', `${apiPrefix}blob/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('GET', `${apiPrefix}tool/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('POST', `${apiPrefix}tool/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('GET', `${apiPrefix}ingest/*`, this.handleApiNotImplemented.bind(this));
    this.addPrefixRoute('POST', `${apiPrefix}ingest/*`, this.handleApiNotImplemented.bind(this));
  }

  private addExactRoute(method: string, pathname: string, handler: RouteHandler): void {
    const existing = this.exactRoutes.get(pathname) ?? [];
    existing.push({ method, handler });
    this.exactRoutes.set(pathname, existing);
  }

  private addPrefixRoute(method: string, prefix: string, handler: RouteHandler): void {
    // Convert `/api/v1/state/*` to prefix `/api/v1/state/`
    const normalizedPrefix = prefix.endsWith('/*') ? prefix.slice(0, -1) : prefix;
    this.prefixRoutes.push({ prefix: normalizedPrefix, method, handler });
  }

  // ── Route Matching ──

  private matchRoute(method: string, pathname: string): { handler: RouteHandler; match: RouteMatch } | null {
    // 1. Exact match
    const entries = this.exactRoutes.get(pathname);
    if (entries) {
      for (const entry of entries) {
        if (entry.method === method || entry.method === '*') {
          return { handler: entry.handler, match: { pathname, params: {} } };
        }
      }
    }

    // 2. Prefix match
    for (const entry of this.prefixRoutes) {
      if (pathname.startsWith(entry.prefix)) {
        if (entry.method === method || entry.method === '*') {
          const wildcard = pathname.substring(entry.prefix.length);
          return {
            handler: entry.handler,
            match: { pathname, params: { wildcard } },
          };
        }
      }
    }

    return null;
  }

  // ── Auth ──

  private checkAuth(req: http.IncomingMessage): { statusCode: number; code: string; message: string } | null {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      this.logPermissionDenied(req, 'Missing or invalid Authorization header');
      return { statusCode: 401, code: 'UNAUTHORIZED', message: 'Missing or invalid Authorization header' };
    }

    const token = authHeader.substring(7);
    if (!this.token) {
      this.logPermissionDenied(req, 'Server token not initialized');
      return { statusCode: 500, code: 'INTERNAL_ERROR', message: 'Server token not initialized' };
    }

    if (token !== this.token) {
      this.logPermissionDenied(req, 'Invalid token');
      return { statusCode: 401, code: 'UNAUTHORIZED', message: 'Invalid token' };
    }

    return null;
  }

  // ── Public API ──

  setEventBus(eventBus: EventBus): void {
    this.eventBus = eventBus;
  }

  setToken(token: string): void {
    this.token = token;
  }

  async start(): Promise<{ port: number }> {
    return new Promise((resolve, reject) => {
      this.startTime = Date.now();

      this.server = http.createServer((req, res) => {
        this.handleRequest(req, res);
      });

      this.server.listen(0, '127.0.0.1', () => {
        const address = this.server?.address();
        if (address && typeof address === 'object') {
          this.port = address.port;
          this.setupGlobalErrorHandlers();
          this.refreshIdleTimeout();
          resolve({ port: this.port });
        } else {
          reject(new Error('Failed to get server port'));
        }
      });

      this.server.on('error', reject);
    });
  }

  async stop(): Promise<void> {
    this.clearIdleTimeout();
    this.stopHeartbeat();
    this.cleanupSseClients();
    this.removeGlobalErrorHandlers();

    return new Promise((resolve, reject) => {
      if (this.server) {
        this.server.close((err) => {
          if (err) reject(err);
          else {
            this.server = null;
            this.port = null;
            resolve();
          }
        });
      } else {
        resolve();
      }
    });
  }

  broadcastEvent(event: Event): void {
    if (this.eventBus) {
      this.eventBus.publish(event);
    }
  }

  // ── Request Handling ──

  private handleRequest(req: http.IncomingMessage, res: http.ServerResponse): void {
    const chunks: Buffer[] = [];

    req.on('data', (chunk: Buffer | string) => {
      chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
    });

    req.on('end', () => {
      const body = Buffer.concat(chunks);
      this.handleRequestWithBody(req, res, body);
    });

    req.on('error', () => {
      this.sendJsonResponse(res, 500, this.errorBody('INTERNAL_ERROR', 'Internal Server Error'));
    });
  }

  private handleRequestWithBody(req: http.IncomingMessage, res: http.ServerResponse, rawBody: Buffer): void {
    try {
      const method = req.method ?? 'GET';
      const pathname = this.getPathname(req);

      // Check payload size
      const maxSize = this.config.getMaxPayloadSize();
      if (rawBody.length > maxSize) {
        this.handleOversizedPayload(req, res, rawBody, maxSize);
        return;
      }

      // CORS preflight
      if (method === 'OPTIONS') {
        this.sendCorsHeaders(res);
        res.writeHead(204);
        res.end();
        return;
      }

      // Auth check (skip for health endpoint)
      if (pathname !== '/health') {
        const authError = this.checkAuth(req);
        if (authError) {
          this.sendJsonResponse(res, authError.statusCode, this.errorBody(authError.code, authError.message));
          return;
        }
      }

      // Parse JSON body for methods with body content
      const bodyString = rawBody.toString('utf-8');
      let parsedBody: unknown = bodyString;
      if (rawBody.length > 0 && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
        const contentType = req.headers['content-type'] ?? '';
        if (contentType.includes('application/json')) {
          try {
            parsedBody = JSON.parse(bodyString);
          } catch {
            this.sendJsonResponse(res, 400, this.errorBody('INVALID_JSON', 'Invalid JSON in request body'));
            return;
          }
        }
      }

      // Route matching
      const matched = this.matchRoute(method, pathname);
      if (!matched) {
        this.sendJsonResponse(res, 404, this.errorBody('NOT_FOUND', `Route ${method} ${pathname} not found`));
        return;
      }

      // Reset idle timeout
      this.refreshIdleTimeout();

      // Execute handler
      const result = matched.handler(req, res, bodyString, matched.match);
      if (result instanceof Promise) {
        result.catch((err: unknown) => {
          this.handleHandlerError(res, err);
        });
      }
    } catch (err: unknown) {
      this.handleHandlerError(res, err);
    }
  }

  private getPathname(req: http.IncomingMessage): string {
    try {
      return new URL(req.url ?? '/', `http://localhost:${this.port ?? 0}`).pathname;
    } catch {
      return '/';
    }
  }

  // ── Response Helpers ──

  private sendJsonResponse(res: http.ServerResponse, statusCode: number, data: unknown): void {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };
    this.addCorsHeaders(headers);
    res.writeHead(statusCode, headers);
    res.end(JSON.stringify(data));
  }

  private addCorsHeaders(headers: Record<string, string>): void {
    headers['Access-Control-Allow-Origin'] = '*';
  }

  private sendCorsHeaders(res: http.ServerResponse): void {
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');
    res.setHeader('Access-Control-Max-Age', '86400');
  }

  private errorBody(code: string, message: string, details?: unknown): Record<string, unknown> {
    const body: Record<string, unknown> = {
      success: false,
      error: { code, message },
      requestId: this.generateRequestId(),
      timestamp: Date.now(),
    };
    if (details !== undefined) {
      (body.error as Record<string, unknown>)['details'] = details;
    }
    return body;
  }

  private successBody<T>(data: T): Record<string, unknown> {
    return {
      success: true,
      data,
      requestId: this.generateRequestId(),
      timestamp: Date.now(),
    };
  }

  // ... handlers
